sysauto_script.script:
var engine = new x_146833_idpkiro.IDPScorecardEngine();

// Get all active scorecards
var scorecards = [];
var gr = new GlideRecord('x_146833_idpkiro_u_idp_scorecard');
gr.addQuery('active', true);
gr.query();

while (gr.next()) {
    scorecards.push({
        sys_id: gr.sys_id.toString(),
        entity_id: gr.entity_id.toString(),
        name: gr.name.toString()
    });
}

// Recalculate each scorecard
var calculatedCount = 0;
for (var i = 0; i < scorecards.length; i++) {
    try {
        var result = engine.calculateScore(scorecards[i].sys_id, scorecards[i].entity_id);
        gs.info('Scorecard "' + scorecards[i].name + '" score: ' + result.score);
        calculatedCount++;
    } catch (e) {
        gs.error('Failed to calculate scorecard ' + scorecards[i].name + ': ' + e.message);
    }
}

gs.info('IDP Scorecard Daily Calculation: Processed ' + calculatedCount + ' scorecards');
